"use client";

import type { ComponentPropsWithoutRef, ReactNode } from "react";

import { cn } from "@/lib/utils";

import { createCompoundContext } from "../_lib/compound";

interface PaymentMethodContextValue {
  name: string;
  onSelect?: (method: string) => void;
  selectedMethod?: string;
}

const { Provider, useCompoundContext } =
  createCompoundContext<PaymentMethodContextValue>("PaymentMethodSelect");

export interface PaymentMethodSelectProps extends Omit<
  ComponentPropsWithoutRef<"div">,
  "onSelect"
> {
  name?: string;
  onSelect?: (method: string) => void;
  selectedMethod?: string;
}

interface OptionProps extends ComponentPropsWithoutRef<"label"> {
  description?: string;
  icon?: ReactNode;
  label?: string;
  value?: string;
}

function Option({
  description,
  icon,
  label = "Payment method",
  value = "method",
  className,
  children,
  ...props
}: OptionProps) {
  const { name, onSelect, selectedMethod } = useCompoundContext();
  return (
    <label
      className={cn(
        "flex cursor-pointer items-center gap-3 rounded-lg border p-3 transition-colors has-[:checked]:border-foreground",
        className
      )}
      {...props}
    >
      <input
        type="radio"
        name={name}
        value={value}
        checked={selectedMethod === value}
        onChange={() => onSelect?.(value)}
      />
      {icon}
      <span className="min-w-0 flex-1">
        <span className="block font-medium">{label}</span>
        {description ? (
          <span className="block text-sm text-muted-foreground">
            {description}
          </span>
        ) : null}
      </span>
      {children}
    </label>
  );
}

function TermsCheckbox({
  className,
  children,
  ...props
}: ComponentPropsWithoutRef<"label">) {
  useCompoundContext();
  return (
    <label
      className={cn(
        "flex items-start gap-2 text-sm text-muted-foreground",
        className
      )}
      {...props}
    >
      <input type="checkbox" className="mt-0.5" />
      <span>{children ?? "I agree to the payment terms"}</span>
    </label>
  );
}

function PaymentMethodSelectRoot({
  name = "payment-method",
  onSelect,
  selectedMethod,
  className,
  children,
  ...props
}: PaymentMethodSelectProps) {
  return (
    <Provider value={{ name, onSelect, selectedMethod }}>
      <div
        className={cn(
          "w-full space-y-3 rounded-xl border bg-card p-4 sm:p-6",
          className
        )}
        {...props}
      >
        {children ?? (
          <>
            <Option
              value="card"
              label="Credit or debit card"
              description="Visa, Mastercard, or Amex"
            />
            <Option
              value="wallet"
              label="Digital wallet"
              description="Apple Pay or Google Pay"
            />
            <Option
              value="bank"
              label="Bank transfer"
              description="Usually arrives in 1–2 business days"
            />
            <TermsCheckbox />
          </>
        )}
      </div>
    </Provider>
  );
}

export const PaymentMethodSelect = Object.assign(PaymentMethodSelectRoot, {
  Option,
  TermsCheckbox,
});

"use client";

import { createContext, createElement, useContext } from "react";
import type { ReactNode } from "react";

import { cn } from "@/lib/utils";

export interface CompoundProviderProps<T> {
  children: ReactNode;
  value: T;
}

export const createCompoundContext = <T,>(name: string) => {
  const Context = createContext<T | null>(null);

  const Provider = ({ value, children }: CompoundProviderProps<T>) =>
    createElement(Context.Provider, { value }, children);

  const useCompoundContext = () => {
    const context = useContext(Context);

    if (!context) {
      throw new Error(`${name} subcomponents must be rendered inside ${name}.`);
    }

    return context;
  };

  return { Provider, useCompoundContext };
};

export const formatPrice = (value: number, currency = "USD") =>
  new Intl.NumberFormat("en-US", {
    currency,
    style: "currency",
  }).format(value);

export type StepStatus = "completed" | "current" | "pending";

export interface TimelineStep {
  description?: string;
  label: string;
  status?: StepStatus;
}

export const statusClasses = (status: StepStatus = "pending") =>
  cn(
    "flex h-6 w-6 items-center justify-center rounded-full text-xs",
    status === "completed" && "bg-foreground text-background",
    status === "current" && "border-2 border-foreground bg-card",
    status === "pending" && "border border-muted-foreground/40 bg-card"
  );

import type { TimelineStep } from "../_lib/compound";

export interface OrderItem {
  image?: string;
  name: string;
  price: number;
  quantity?: number;
  sku?: string;
  variant?: string;
}

export interface PaymentMethod {
  description?: string;
  label: string;
  value: string;
}

export interface RefundDetails {
  amount: number;
  steps: TimelineStep[];
}
